using System.Text.Json;
using System.Text.Json.Serialization;
using System.Text.Json.Serialization.Metadata;

// --- 1. GetTypeInfo<T>(): strongly-typed metadata retrieval ---

var options = new JsonSerializerOptions(JsonSerializerDefaults.Web);

JsonTypeInfo<Person> personInfo = options.GetTypeInfo<Person>();
Console.WriteLine($"GetTypeInfo<Person>() returned metadata for: {personInfo.Type.Name}");

string json = JsonSerializer.Serialize(new Person("Ada", 36), personInfo);
Console.WriteLine($"Serialized: {json}");

Person? round = JsonSerializer.Deserialize(json, personInfo);
Console.WriteLine($"Deserialized: {round}");

// --- 2. TryGetTypeInfo<T>(): probe without throwing ---

// This resolver only knows about Person – it will NOT resolve Order.
var limited = new JsonSerializerOptions
{
    TypeInfoResolver = new DefaultJsonTypeInfoResolver()
};

if (limited.TryGetTypeInfo<Person>(out JsonTypeInfo<Person>? pInfo))
{
    Console.WriteLine($"\nTryGetTypeInfo<Person> succeeded – Type: {pInfo!.Type.Name}");
}

// Use a resolver that resolves nothing, so Order metadata is unavailable.
var empty = new JsonSerializerOptions
{
    TypeInfoResolver = JsonTypeInfoResolver.Combine() // no resolvers → resolves nothing
};

if (empty.TryGetTypeInfo<Order>(out JsonTypeInfo<Order>? oInfo))
{
    Console.WriteLine($"TryGetTypeInfo<Order> succeeded – Type: {oInfo!.Type.Name}");
}
else
{
    Console.WriteLine("\nTryGetTypeInfo<Order> returned false – no metadata available (no exception thrown)");
}

// --- Types ---

public record Person(string Name, int Age);
public record Order(int Id, decimal Total);

